import sqlite3

def get_order_info(user_id, order_id):
    conn = sqlite3.connect('database_name.db')  # replace 'database_name' with your database name
    c = conn.cursor()
    
    query = "SELECT * FROM orders WHERE user_id=? AND order_id=?"
    params = (user_id, order_id)
    
    c.execute(query, params)
    
    data = {}
    for row in c:
        data['order_id'] = row[0]
        data['user_id'] = row[1]
        # replace 'column3' and 'column4' with actual column names in your database 
        data['column3'] = row[2]  
        data['column4'] = row[3]   
    
    conn.close()
    
    return data